#include <iostream>
#include <unordered_map>
#include <string>
#include <chrono>

struct PlayerStats {
    int health;
    int attack;
    int defense;
    int level;
};

int main() {
    std::cout << "=== std::unordered_map — Fast Lookups ===" << std::endl;

    // 1. Creating unordered_map
    std::cout << "\n--- Creating unordered_map ---" << std::endl;
    std::unordered_map<std::string, int> scores = {
        {"Hero", 100},
        {"Aragorn", 85},
        {"Gandalf", 95},
        {"Legolas", 90}
    };

    // 2. Accessing elements (O(1) average)
    std::cout << "\n--- Accessing elements ---" << std::endl;
    std::cout << "Hero's score: " << scores["Hero"] << std::endl;
    std::cout << "Gandalf's score: " << scores["Gandalf"] << std::endl;

    // 3. Adding and updating
    std::cout << "\n--- Adding and updating ---" << std::endl;
    scores["Frodo"] = 80;  // Add
    scores["Hero"] = 120; // Update

    for (const auto& pair : scores) {
        std::cout << pair.first << ": " << pair.second << std::endl;
    }

    // 4. Checking existence
    std::cout << "\n--- Checking existence ---" << std::endl;
    if (scores.find("Sam") != scores.end()) {
        std::cout << "Sam has a score" << std::endl;
    } else {
        std::cout << "Sam not found" << std::endl;
    }

    // 5. Removing
    std::cout << "\n--- Removing ---" << std::endl;
    scores.erase("Legolas");
    std::cout << "After erasing Legolas:" << std::endl;
    for (const auto& pair : scores) {
        std::cout << pair.first << ": " << pair.second << std::endl;
    }

    // 6. Game use: player stats lookup
    std::cout << "\n--- Player Stats (unordered_map) ---" << std::endl;
    std::unordered_map<std::string, PlayerStats> players;

    players["Hero"] = {100, 20, 15, 5};
    players["Goblin"] = {30, 8, 3, 1};
    players["Boss"] = {200, 30, 20, 10};

    std::string playerName = "Boss";
    if (players.find(playerName) != players.end()) {
        const PlayerStats& stats = players[playerName];
        std::cout << playerName << " stats:" << std::endl;
        std::cout << "  Health: " << stats.health << std::endl;
        std::cout << "  Attack: " << stats.attack << std::endl;
        std::cout << "  Defense: " << stats.defense << std::endl;
        std::cout << "  Level: " << stats.level << std::endl;
    }

    // 7. Map vs Unordered Map
    std::cout << "\n--- std::map vs std::unordered_map ---" << std::endl;
    std::cout << "std::map:" << std::endl;
    std::cout << "  • Sorted order" << std::endl;
    std::cout << "  • O(log n) lookup" << std::endl;
    std::cout << "  • Less memory overhead" << std::endl;
    std::cout << "\nstd::unordered_map:" << std::endl;
    std::cout << "  • No order" << std::endl;
    std::cout << "  • O(1) average lookup" << std::endl;
    std::cout << "  • More memory overhead" << std::endl;

    std::cout << "\nUse unordered_map when you need FAST lookups and don't care about order." << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <unordered_map>

struct Point {
    int x, y;
};

int main() {
    std::unordered_map<Point, std::string> positions;

    Point p{10, 20};
    positions[p] = "Hero";  // ERROR! No hash for Point!

    return 0;
}

phase2.explanation:
You can't use a custom type as a key in `unordered_map` without providing a hash function!

**The fix:**
```cpp
struct PointHash {
    std::size_t operator()(const Point& p) const {
        return std::hash<int>()(p.x) ^ (std::hash<int>()(p.y) << 1);
    }
};

std::unordered_map<Point, std::string, PointHash> positions;
```

**PlusPlus-chan says:**
"For custom types, you need a hash function. Or use `std::map`, which only needs `operator<`."

