#include <iostream>
#include <unordered_map>
#include <string>

int main() {
    std::unordered_map<std::string, int> highScores;

    highScores["Hero"] = 1000;
    highScores["Aragorn"] = 850;
    highScores["Gandalf"] = 950;

    std::cout << "=== High Scores ===" << std::endl;
    for (const auto& entry : highScores) {
        std::cout << entry.first << ": " << entry.second << std::endl;
    }

    if (highScores.find("Legolas") != highScores.end()) {
        std::cout << "\nLegolas found!" << std::endl;
    } else {
        std::cout << "\nLegolas not found" << std::endl;
    }

    highScores["Hero"] = 1200;
    highScores["Legolas"] = 700;
    highScores.erase("Aragorn");

    std::cout << "\nFinal High Scores (size: " << highScores.size() << "):" << std::endl;
    for (const auto& entry : highScores) {
        std::cout << entry.first << ": " << entry.second << std::endl;
    }

    return 0;
}
